<?php
declare(strict_types=1);require dirname(__DIR__).'/config/config.php';require dirname(__DIR__).'/vendor/autoload.php';use App\Core\Database;use App\Services\ControlEscaneres\Schema\{ControlEscaneresSchemaInspector,LocalExecutionGuard,MigrationManifestVerifier};$root=dirname(__DIR__);$args=array_slice($argv,1);$execute=in_array('--execute',$args,true);$confirm=in_array('--confirm-local',$args,true);$interactive=function_exists('stream_isatty')&&stream_isatty(STDIN);$ciLocal=in_array('--ci-local',$args,true);$value=function(string$prefix)use($args):?string{foreach($args as$a)if(str_starts_with($a,$prefix.'='))return substr($a,strlen($prefix)+1);return null;};$backupChecksum=$value('--backup-checksum');$expectedDb=$value('--database');$manifest=$root.'/database/migrations/control-escaneres/manifest.json';
try{$rows=(new MigrationManifestVerifier())->verify($manifest,$root.'/database/migrations');$manifestValid=!array_filter($rows,fn($x)=>!$x['valid']);echo'Modo: '.($execute?'EXECUTE LOCAL':'DRY-RUN').PHP_EOL;foreach($rows as$r)echo'['.($r['valid']?'PASS':'BLOCKED').'] '.$r['order'].' '.$r['file'].' sha256='.substr($r['checksum'],0,12).' dependencia='.($r['depends_on']??'ninguna').PHP_EOL;if(!$manifestValid)exit(2);if(!$execute){echo'[PASS] Orden y checksums verificados. No se ejecutó SQL.'.PHP_EOL;exit(0);}
    $backupValid=false;foreach(glob($root.'/storage/backups/database/*.sql')?:[]as$file)if($backupChecksum!==null&&hash_equals($backupChecksum,hash_file('sha256',$file)))$backupValid=true;$pdo=Database::getConnection();$inspection=(new ControlEscaneresSchemaInspector())->inspect($pdo);(new LocalExecutionGuard())->assert(['env'=>getenv('APP_ENV')?:'','host'=>DB_HOST,'database'=>DB_NAME,'expected_database'=>$expectedDb,'execute'=>$execute,'confirm_local'=>$confirm,'interactive'=>$interactive||$ciLocal,'manifest_valid'=>$manifestValid,'backup_valid'=>$backupValid,'preflight_allowed'=>$inspection->exitCode()<2]);
    $pdo->exec("CREATE TABLE IF NOT EXISTS schema_migrations(id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,module VARCHAR(80) NOT NULL,migration_name VARCHAR(190) NOT NULL,checksum CHAR(64) NOT NULL,applied_at DATETIME(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),execution_id VARCHAR(64) NOT NULL,PRIMARY KEY(id),UNIQUE KEY uq_schema_migrations_module_name(module,migration_name)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$executionId=bin2hex(random_bytes(16));
    foreach($rows as$r){$check=$pdo->prepare('SELECT checksum FROM schema_migrations WHERE module=:module AND migration_name=:name');$check->execute(['module'=>'control-escaneres','name'=>$r['file']]);$applied=$check->fetchColumn();if($applied!==false){if(!hash_equals($r['checksum'],(string)$applied))throw new DomainException('Checksum registrado no coincide: '.$r['file']);echo'[SKIP] '.$r['file'].' ya aplicada.'.PHP_EOL;continue;}echo'[PENDING] '.$r['order'].' '.$r['file'].' '.substr($r['checksum'],0,12).PHP_EOL;$start=microtime(true);$pdo->exec((string)file_get_contents($root.'/database/migrations/'.$r['file']));$record=$pdo->prepare('INSERT INTO schema_migrations(module,migration_name,checksum,execution_id)VALUES(:module,:name,:checksum,:execution)');$record->execute(['module'=>'control-escaneres','name'=>$r['file'],'checksum'=>$r['checksum'],'execution'=>$executionId]);echo'[APPLIED] '.$r['file'].' duration_ms='.(int)((microtime(true)-$start)*1000).' execution_id='.$executionId.PHP_EOL;}
    echo'[PASS] Migración local completada.'.PHP_EOL;exit(0);
}catch(DomainException$e){fwrite(STDERR,'[BLOCKED] '.$e->getMessage().PHP_EOL);exit(2);}catch(Throwable$e){fwrite(STDERR,'[ERROR] Ejecución detenida en el primer fallo: '.get_class($e).PHP_EOL);exit(3);}
